import{_ as e,o as a,c as o,ae as i}from"./chunks/framework.Czhw_PXq.js";const f=JSON.parse('{"title":"YApi Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/yapi.md","filePath":"settings/yapi.md","lastUpdated":1776813413000}'),r={name:"settings/yapi.md"};function d(n,t,s,p,l,h){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="yapi-settings" tabindex="-1">YApi Settings <a class="header-anchor" href="#yapi-settings" aria-label="Permalink to &quot;YApi Settings&quot;">​</a></h1><h2 id="ide-settings" tabindex="-1">IDE Settings <a class="header-anchor" href="#ide-settings" aria-label="Permalink to &quot;IDE Settings&quot;">​</a></h2><p>Configure YApi settings in the IDE:</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; <kbd>YApi</kbd></p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Yapi Server</td><td>YApi server address</td></tr><tr><td>Tokens</td><td>Project tokens in <code>module=token</code> format (one per line)</td></tr><tr><td>Export Mode</td><td>How to handle existing APIs on export (see below)</td></tr><tr><td>Request body JSON5</td><td>Use JSON5 format for request body (default: off)</td></tr><tr><td>Response body JSON5</td><td>Use JSON5 format for response body (default: off)</td></tr></tbody></table><p>Additional options in the <strong>General</strong> tab:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Enable URL Templating</td><td><code>true</code></td><td>Enable URL templating for path parameters</td></tr><tr><td>Switch Notice</td><td><code>true</code></td><td>Show notification when switching YApi project</td></tr></tbody></table><h3 id="getting-a-yapi-token" tabindex="-1">Getting a YApi Token <a class="header-anchor" href="#getting-a-yapi-token" aria-label="Permalink to &quot;Getting a YApi Token&quot;">​</a></h3><ol><li>Log in to YApi</li><li>Go to project settings</li><li>Copy the project Token</li></ol><h3 id="token-format" tabindex="-1">Token Format <a class="header-anchor" href="#token-format" aria-label="Permalink to &quot;Token Format&quot;">​</a></h3><p>Tokens are specified as <code>module=token</code> pairs, one per line in the IDE Tokens field. The module name is used to match APIs to the correct YApi project.</p><h3 id="export-mode" tabindex="-1">Export Mode <a class="header-anchor" href="#export-mode" aria-label="Permalink to &quot;Export Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>ALWAYS_UPDATE</td><td>Always update existing APIs (default)</td></tr><tr><td>NEVER_UPDATE</td><td>Never update existing APIs</td></tr><tr><td>ALWAYS_ASK</td><td>Show a dialog to ask whether to override each API</td></tr><tr><td>UPDATE_IF_CHANGED</td><td>Update only when the API content has changed</td></tr></tbody></table><h2 id="config-file-rules" tabindex="-1">Config File Rules <a class="header-anchor" href="#config-file-rules" aria-label="Permalink to &quot;Config File Rules&quot;">​</a></h2><p>The following rules can be set in config files (<code>.easy.api.config</code>):</p><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td><a href="/settings/rules/yapi_project">yapi.project</a></td><td>Set the YApi project for API grouping</td></tr><tr><td><a href="/settings/events/yapi_export_before">yapi.export.before</a></td><td>Event before YApi export</td></tr><tr><td><a href="/settings/rules/yapi_save_before">yapi.save.before</a></td><td>Event before saving to YApi</td></tr><tr><td><a href="/settings/rules/yapi_save_after">yapi.save.after</a></td><td>Event after saving to YApi</td></tr></tbody></table><h2 id="yapi-mock" tabindex="-1">YApi Mock <a class="header-anchor" href="#yapi-mock" aria-label="Permalink to &quot;YApi Mock&quot;">​</a></h2><p>EasyYapi supports syncing field mock rules to the YApi Mock service.</p><p>See <a href="./yapi-mock">YApi Mock</a> for details.</p>',19)])])}const b=e(r,[["render",d]]);export{f as __pageData,b as default};
